SELECT AVG(moses_bleu) AS average_moses_bleu
FROM hyperparameters
WHERE sparsity > 0.5;

SELECT e.experiment_name, h.moses_bleu
FROM experiments e
JOIN hyperparameters h ON e.experiment_id = h.experiment_id;

SELECT AVG(experiment_count) AS average_experiments_per_user
FROM (
  SELECT e.created_by, COUNT(e.experiment_id) AS experiment_count
  FROM experiments e
  GROUP BY e.created_by
) AS user_experiment_counts;

SELECT AVG(h.moses_bleu) AS average_moses_bleu
FROM hyperparameters h
INNER JOIN pruning_details p ON h.experiment_id = p.experiment_id;

SELECT AVG(h.moses_bleu) AS avg_moses_bleu
FROM hyperparameters h
JOIN pruning_details p ON h.experiment_id = p.experiment_id;
